'use client';

import { useState } from 'react';
import { useLanguage } from '@/hooks/useLanguage';
import { Mail, MessageCircle, Phone } from 'lucide-react';

export default function ServiceCTA() {
  const { t } = useLanguage();
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    message: '',
  });

  const handleChange = (
    e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>
  ) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    console.log('Form submitted:', formData);
    setFormData({ name: '', email: '', message: '' });
  };

  return (
    <section className="service-cta-section">
      <h2
        dangerouslySetInnerHTML={{ __html: t('cta.title') }}
      />

      <div className="service-cta-content" style={{ marginTop: '2rem' }}>
        <div className="service-cta-left">
          <a href="mailto:hello@goopti.com" className="service-contact-link">
            <Mail size={24} />
            <span>hello@goopti.com</span>
          </a>
          <a href="https://wa.me/33712345678" className="service-contact-link" target="_blank">
            <MessageCircle size={24} />
            <span>WhatsApp</span>
          </a>
          <a href="tel:+33712345678" className="service-contact-link">
            <Phone size={24} />
            <span>+33 7 12 34 56 78</span>
          </a>
        </div>

        <form onSubmit={handleSubmit} className="contact-form">
          <div className="form-group">
            <input
              type="text"
              name="name"
              placeholder={t('cta.form.name')}
              value={formData.name}
              onChange={handleChange}
              required
            />
          </div>
          <div className="form-group">
            <input
              type="email"
              name="email"
              placeholder={t('cta.form.email')}
              value={formData.email}
              onChange={handleChange}
              required
            />
          </div>
          <div className="form-group">
            <textarea
              name="message"
              placeholder={t('cta.form.message')}
              value={formData.message}
              onChange={handleChange}
              rows={4}
              required
            />
          </div>
          <button type="submit" className="contact-submit">
            {t('cta.form.send')}
          </button>
        </form>
      </div>
    </section>
  );
}
