'use client';

import { services } from '@/lib/services';
import { useLanguage } from '@/hooks/useLanguage';
import ServiceCard from '../ServiceCard';

interface RelatedServicesProps {
  relatedSlugs: string[];
}

export default function RelatedServices({ relatedSlugs }: RelatedServicesProps) {
  const { language } = useLanguage();

  const relatedServices = services.filter((s) => relatedSlugs.includes(s.slug));

  return (
    <section className="related-services">
      <div style={{ maxWidth: '1200px', margin: '0 auto' }}>
        <h2>Autres services qui pourraient vous intéresser</h2>

        <div className="services-grid" style={{ marginTop: '2rem' }}>
          {relatedServices.map((service) => (
            <ServiceCard
              key={service.slug}
              slug={service.slug}
              icon={service.icon}
              title={service.content[language].title}
              externalLink={service.externalLink}
            />
          ))}
        </div>
      </div>
    </section>
  );
}
